@import url("https://fonts.googleapis.com/css2?family=Geist:wght@100;200;300;400;500;600;700;800;900&display=swap");
*,*::before,*::after{margin:0;padding:0;box-sizing:border-box}
:root{--bg:#0b080c;--fg:#eae5ec;--accent:#c2a4ff;--muted:#8b7fa8;--border:rgba(255,255,255,0.08);--surface:rgba(255,255,255,0.04);--font:"Geist",sans-serif}
html{scroll-behavior:smooth;scrollbar-width:thin;scrollbar-color:var(--accent) transparent}
body{font-family:var(--font);background:var(--bg);color:var(--fg);overflow-x:hidden}
a{text-decoration:none;color:inherit}
.section-container{width:1200px;max-width:calc(100% - 80px);margin:0 auto}
@media(max-width:900px){.section-container{width:100%;max-width:calc(100% - 40px)}}

/* LOADING */
.loading-screen{position:fixed;width:100vw;height:100vh;background:#eae5ec;z-index:999999;display:flex;place-items:center;justify-content:center;flex-direction:column}
.loading-header{width:calc(100% - 60px);max-width:1920px;position:fixed;z-index:9999999;display:flex;justify-content:space-between;padding:20px 0;left:50%;transform:translate(-50%);top:0;color:#0b080c}
.loader-title{font-weight:700;font-size:16px;letter-spacing:.2px;color:#0b080c;text-decoration:none}
.loaderGame-container{width:200px;height:100px;overflow:hidden;position:relative;transform:scale(.4);transform-origin:top right}
.loaderGame-in{width:1200px;position:absolute;overflow:hidden;left:0;animation:lgame 7s linear infinite}
@keyframes lgame{0%{transform:translate(0)}to{transform:translate(-300px)}}
.loaderGame-line{float:left;margin:0 20px 40px;position:relative;width:10px;height:60px;background:#0b080c;display:block}
.loaderGame-line:nth-child(2n){margin-top:40px;margin-bottom:0}
.loaderGame-ball{position:absolute;left:20%;top:0;width:15px;height:15px;border-radius:50%;background:#a87cff;animation:lball 7s infinite;transform:translateY(10px);animation-timing-function:cubic-bezier(.3,1.18,.63,1.28)}
@keyframes lball{0%{transform:translateY(70px)}15%{transform:translateY(10px)}30%{transform:translateY(70px)}45%{transform:translateY(10px)}67%{transform:translateY(70px)}80%{transform:translateY(10px)}to{transform:translateY(70px)}}
.loading-marquee{position:absolute;top:50%;left:0;width:100%;transform:translateY(-50%);color:#0b080c;font-size:60px;font-weight:600;text-transform:uppercase;overflow:hidden;white-space:nowrap}
.marquee-inner{display:inline-flex;gap:60px;animation:mq 12s linear infinite}
@keyframes mq{0%{transform:translateX(0)}to{transform:translateX(-50%)}}
.marquee-inner span{padding:0 30px}.marquee-inner .dot{opacity:.4}
.loading-wrap{--Lsize:165px;padding:6px;position:relative;border-radius:100px;background:#000;overflow:hidden;transition:.8s ease-in-out .2s;display:flex;justify-content:center;align-items:center;box-shadow:0 15px 15px #0003}
.loading-wrap.clicked{transition-delay:0ms;transition-timing-function:cubic-bezier(.33,.11,1,.72);min-width:calc(100vw + 5000px);border-radius:5000px;min-height:calc(100vh + 500px);box-shadow:none}
.loading-hover{background:#a87cff;width:250px;height:120px;position:absolute;top:var(--mouse-y,50%);left:var(--mouse-x,50%);border-radius:50%;transform:translate(-50%,-50%);filter:blur(30px);opacity:0;transition:opacity .5s;pointer-events:none}
.loading-wrap:hover .loading-hover{opacity:1}
.loading-wrap.clicked .loading-hover{opacity:0}
.loading-button{padding:20px 50px;border-radius:100px;background:#000;font-size:18px;font-weight:500;position:relative;z-index:9;color:#eae5ec;display:flex;align-items:center;gap:20px;overflow:hidden}
.loading-container{position:relative;z-index:9}
.loading-content-in{font-size:18px;font-weight:500;white-space:nowrap;color:#eae5ec}
.loading-box{width:15px;height:25px;background:#fff;animation:blink 1s linear infinite}
@keyframes blink{0%{opacity:0}25%{opacity:1}75%{opacity:1}to{opacity:0}}
.loading-content2{font-size:18px;font-weight:500;overflow:hidden;max-height:0;opacity:0;transition:max-height .5s,opacity .5s}
.loading-complete .loading-content2{max-height:40px;opacity:1}
.loading-complete .loading-container{opacity:0;transition:.3s}
.loading-complete .loading-box{animation:none;opacity:0}

/* NAVBAR */
#navbar{position:fixed;top:0;width:100%;z-index:10000;padding:20px 0;transition:all .4s}
#navbar.scrolled{background:rgba(11,8,12,.9);backdrop-filter:blur(20px);border-bottom:1px solid var(--border)}
.nav-inner{display:flex;align-items:center;justify-content:space-between;width:calc(100% - 80px);max-width:1920px;margin:0 auto}
.nav-logo{font-size:1.6rem;font-weight:800;color:var(--fg);letter-spacing:-.05em}
.accent-dot{color:var(--accent)}
.nav-links{display:flex;gap:2.5rem}
.nav-links a{font-size:.9rem;font-weight:500;color:var(--muted);transition:color .3s;letter-spacing:.5px}
.nav-links a:hover{color:var(--fg)}
.nav-right{display:flex;align-items:center;gap:1.2rem}
.nav-resume{padding:.5rem 1.2rem;border:1px solid var(--border);border-radius:8px;font-size:.85rem;font-weight:600;color:var(--fg);display:flex;align-items:center;gap:.4rem;transition:all .3s}
.nav-resume:hover{border-color:var(--accent);color:var(--accent);box-shadow:0 0 20px rgba(194,164,255,.2)}
.nav-burger{display:none;background:none;border:none;color:var(--fg);font-size:1.8rem;cursor:pointer}
.mobile-nav{display:none;position:fixed;inset:0;background:rgba(11,8,12,.97);backdrop-filter:blur(20px);z-index:99999;flex-direction:column;align-items:center;justify-content:center;gap:2rem}
.mobile-nav.open{display:flex}
.mobile-close{position:absolute;top:2rem;right:2rem;background:none;border:none;color:var(--fg);font-size:2rem;cursor:pointer}
.mobile-links{display:flex;flex-direction:column;align-items:center;gap:2rem}
.mobile-link{font-size:2.5rem;font-weight:700;color:var(--fg);text-transform:uppercase;letter-spacing:-.03em;transition:color .3s}
.mobile-link:hover{color:var(--accent)}
@media(max-width:768px){.nav-links,.nav-resume{display:none}.nav-burger{display:block}}

/* HERO */
#hero{min-height:100vh;position:relative;display:flex;align-items:center;padding:8rem 0 4rem;overflow:hidden}
#heroCanvas{position:absolute;inset:0;z-index:0;pointer-events:none}
.hero-inner{position:relative;z-index:1;display:grid;grid-template-columns:1fr 420px;grid-template-rows:auto;gap:3rem;align-items:center}
.hero-top{grid-column:1;display:flex;gap:1rem;flex-wrap:wrap;margin-bottom:.5rem}
.hero-status{display:inline-flex;align-items:center;gap:.5rem;padding:.4rem .9rem;background:rgba(34,197,94,.08);border:1px solid rgba(34,197,94,.2);border-radius:40px;font-size:.75rem;font-weight:600;color:#22c55e}
.status-dot{width:7px;height:7px;border-radius:50%;background:#22c55e;box-shadow:0 0 10px #22c55e;animation:sdot 2s infinite}
@keyframes sdot{0%,100%{opacity:1}50%{opacity:.4}}
.hero-loc{display:inline-flex;align-items:center;gap:.4rem;padding:.4rem .9rem;background:var(--surface);border:1px solid var(--border);border-radius:40px;font-size:.75rem;color:var(--muted)}
.hero-name-wrap{grid-column:1}
.hero-name-line{overflow:hidden;line-height:.92}
.name-word{display:inline-block;font-size:clamp(4.5rem,9vw,9rem);font-weight:800;letter-spacing:-.04em;text-transform:uppercase;animation:slideUp .9s cubic-bezier(.19,1,.22,1) both}
.hero-name-line:nth-child(2) .name-word{animation-delay:.12s}
.name-word.stroke{-webkit-text-stroke:2px var(--fg);color:transparent}
@keyframes slideUp{from{transform:translateY(110%);opacity:0}to{transform:translateY(0);opacity:1}}
.hero-sub{grid-column:1;font-family:monospace;font-size:clamp(1rem,2vw,1.3rem);color:var(--accent);display:flex;align-items:center;gap:.5rem;min-height:2rem}
.typed-prefix{color:#ec4899;font-weight:700}
.type-cursor{animation:cur 1s step-end infinite}
@keyframes cur{50%{opacity:0}}
.hero-stats-row{grid-column:1;display:flex;align-items:center;gap:2rem;flex-wrap:wrap}
.hstat{display:flex;align-items:baseline;gap:.3rem;flex-direction:column}
.hstat-num{font-size:2.5rem;font-weight:800;line-height:1;color:var(--fg)}
.hstat-plus{font-size:1.5rem;font-weight:800;color:var(--accent);margin-left:1px}
.hstat-label{font-size:.7rem;text-transform:uppercase;letter-spacing:.1em;color:var(--muted)}
.hstat-sep{width:1px;height:36px;background:var(--border)}
.hero-cta{grid-column:1;display:flex;gap:1rem;flex-wrap:wrap}
.btn-primary{padding:.9rem 2rem;background:var(--accent);border:none;border-radius:10px;font-weight:700;font-size:.95rem;color:#0b080c;cursor:pointer;display:inline-flex;align-items:center;gap:.6rem;transition:all .3s;font-family:var(--font)}
.btn-primary:hover{transform:translateY(-3px);box-shadow:0 12px 30px rgba(194,164,255,.35)}
.btn-outline{padding:.9rem 2rem;background:transparent;border:1px solid var(--border);border-radius:10px;font-weight:600;font-size:.95rem;color:var(--fg);display:inline-flex;align-items:center;gap:.6rem;transition:all .3s}
.btn-outline:hover{border-color:var(--fg);transform:translateY(-3px)}
.btn-primary.full{width:100%;justify-content:center;padding:1.1rem;font-size:1rem}
.hero-photo-wrap{grid-column:2;grid-row:1/7;display:flex;align-items:center;justify-content:center}
.hero-photo-frame{position:relative;width:380px;height:460px;border-radius:24px;overflow:visible}
.hero-photo{width:100%;height:100%;object-fit:cover;border-radius:24px;border:1px solid var(--border);filter:contrast(1.05) brightness(1.05)}
.photo-glow{position:absolute;inset:-20px;background:radial-gradient(circle,rgba(194,164,255,.25),transparent 70%);filter:blur(30px);z-index:-1;border-radius:24px}
.photo-tag{position:absolute;padding:.55rem 1rem;background:rgba(11,8,12,.85);border:1px solid var(--border);border-radius:12px;backdrop-filter:blur(12px);font-size:.8rem;font-weight:600;display:flex;align-items:center;gap:.5rem;white-space:nowrap}
.photo-tag i{color:var(--accent);font-size:1rem}
.tag1{top:30px;right:-20px}
.tag2{bottom:50px;left:-30px}
.tag2 i{color:#f59e0b}
.scroll-arrow{position:absolute;bottom:2rem;left:50%;transform:translateX(-50%);font-size:1.5rem;color:var(--muted);animation:bounce 2s infinite}
@keyframes bounce{0%,100%{transform:translateX(-50%) translateY(0)}50%{transform:translateX(-50%) translateY(10px)}}
@media(max-width:900px){.hero-inner{grid-template-columns:1fr}.hero-photo-wrap{grid-column:1;grid-row:auto;margin-top:2rem}.hero-photo-frame{width:100%;max-width:300px;height:360px;margin:0 auto}}

/* SECTIONS */
.section{padding:8rem 0;position:relative}
.sec-label{font-size:.75rem;font-weight:600;letter-spacing:.15em;text-transform:uppercase;color:var(--muted);margin-bottom:1.5rem;display:flex;align-items:center;gap:.5rem}
.sec-label::before{content:'';display:block;width:24px;height:1px;background:var(--muted)}
.sec-title{font-size:clamp(2.5rem,5vw,4rem);font-weight:800;line-height:1.05;letter-spacing:-.04em;margin-bottom:3rem}
.grad{background:linear-gradient(135deg,var(--accent),#ec4899);-webkit-background-clip:text;-webkit-text-fill-color:transparent}
.reveal{opacity:0;transform:translateY(40px);transition:all .8s cubic-bezier(.19,1,.22,1)}
.reveal.in{opacity:1;transform:translateY(0)}
.delay1{transition-delay:.12s!important}
.delay2{transition-delay:.22s!important}
.delay3{transition-delay:.32s!important}

/* ABOUT */
.about-grid{display:grid;grid-template-columns:1fr 1fr;gap:5rem;align-items:center}
.sec-para{font-size:1.05rem;color:var(--muted);line-height:1.9;margin-bottom:2rem}
.about-chips{display:flex;flex-wrap:wrap;gap:.8rem;margin-bottom:2rem}
.about-chips span{padding:.45rem 1rem;background:var(--surface);border:1px solid var(--border);border-radius:8px;font-size:.85rem;color:var(--fg);display:flex;align-items:center;gap:.5rem}
.about-chips span i{color:var(--accent)}
.about-socials{display:flex;gap:.8rem}
.soc-link{width:44px;height:44px;border-radius:10px;border:1px solid var(--border);display:flex;align-items:center;justify-content:center;font-size:1.3rem;color:var(--muted);transition:all .3s;background:var(--surface)}
.soc-link.lg{width:52px;height:52px;font-size:1.5rem}
.soc-link:hover{background:var(--accent);border-color:var(--accent);color:#0b080c;transform:translateY(-4px)}
.award-grid{display:grid;grid-template-columns:1fr 1fr;gap:1rem}
.award-card{background:var(--surface);border:1px solid var(--border);padding:1.5rem;border-radius:16px;display:flex;align-items:center;gap:1rem;transition:all .4s cubic-bezier(.19,1,.22,1);cursor:default}
.award-card:hover{transform:translateY(-5px);border-color:rgba(194,164,255,.2);background:rgba(255,255,255,.06)}
.aw-icon{width:48px;height:48px;border-radius:12px;display:flex;align-items:center;justify-content:center;font-size:1.4rem;flex-shrink:0}
.aw-icon.gold{background:rgba(245,158,11,.1);color:#f59e0b}
.aw-icon.green{background:rgba(34,197,94,.1);color:#22c55e}
.aw-icon.purple{background:rgba(194,164,255,.1);color:var(--accent)}
.aw-icon.cyan{background:rgba(6,182,212,.1);color:#06b6d4}
.aw-body{display:flex;flex-direction:column}
.aw-body strong{font-size:1.05rem;font-weight:700;color:var(--fg)}
.aw-body span{font-size:.8rem;color:var(--muted)}
@media(max-width:768px){.about-grid{grid-template-columns:1fr;gap:3rem}}

/* EXPERIENCE */
.exp-list{display:flex;flex-direction:column;gap:1.5rem}
.exp-item{display:flex;gap:0;background:var(--surface);border:1px solid var(--border);border-radius:18px;overflow:hidden;transition:all .4s cubic-bezier(.19,1,.22,1)}
.exp-item:hover{border-color:rgba(194,164,255,.25);transform:translateX(8px);background:rgba(255,255,255,.05)}
.exp-left{display:flex;flex-direction:column;align-items:center;padding:2rem 1.5rem 2rem 2rem}
.exp-logo{width:56px;height:56px;border-radius:14px;background:linear-gradient(135deg,var(--lg));display:flex;align-items:center;justify-content:center;font-size:1.7rem;color:#fff;flex-shrink:0}
.exp-line{flex:1;width:2px;background:linear-gradient(to bottom,var(--border),transparent);margin:1rem auto 0}
.exp-right{padding:2rem 2rem 2rem 0;flex:1}
.exp-hdr{display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:1.5rem;gap:1rem;flex-wrap:wrap}
.exp-hdr h3{font-size:1.4rem;font-weight:700;margin-bottom:.4rem}
.exp-role{display:flex;align-items:center;gap:.5rem;font-size:.9rem;color:var(--fg);margin-bottom:.3rem}
.exp-role i{color:var(--accent)}
.exp-date{display:flex;align-items:center;gap:.5rem;font-size:.78rem;color:var(--muted);font-family:monospace}
.exp-date i{color:var(--muted)}
.exp-badge{padding:.35rem .8rem;border-radius:20px;font-size:.72rem;font-weight:600;display:flex;align-items:center;gap:.35rem;white-space:nowrap}
.exp-badge.live{background:rgba(34,197,94,.1);color:#22c55e;border:1px solid rgba(34,197,94,.2)}
.exp-badge.done{background:rgba(148,163,184,.08);color:var(--muted);border:1px solid var(--border)}
.exp-metrics{display:flex;gap:1rem;margin-bottom:1.5rem;flex-wrap:wrap}
.metric{background:rgba(0,0,0,.3);padding:.8rem 1.2rem;border-radius:10px;border:1px solid var(--border);display:flex;flex-direction:column;gap:.2rem;flex:1;min-width:130px}
.metric.full{min-width:100%}
.metric strong{font-size:1.2rem;font-weight:800;color:var(--accent)}
.metric span{font-size:.78rem;color:var(--muted)}
.exp-tags{display:flex;flex-wrap:wrap;gap:.5rem}
.exp-tags span{padding:.28rem .7rem;background:rgba(255,255,255,.03);border:1px solid var(--border);border-radius:6px;font-size:.73rem;font-family:monospace;color:var(--fg)}
@media(max-width:600px){.exp-left{display:none}.exp-right{padding:1.5rem}.exp-item:hover{transform:none}}

/* TECH STACK */
.techstack{width:100%;min-height:100vh;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:8rem 0;background:linear-gradient(180deg,var(--bg),#0e0b10);position:relative;overflow:hidden}
.techstack::before{content:'';position:absolute;inset:0;background:radial-gradient(circle at 20% 50%,rgba(194,164,255,.07) 0%,transparent 50%),radial-gradient(circle at 80% 50%,rgba(194,164,255,.05) 0%,transparent 50%);pointer-events:none}
#stackCanvas{position:absolute;inset:0;opacity:.4;pointer-events:none}
.techstack-title{font-size:clamp(3rem,7vw,7rem);font-weight:800;text-align:center;text-transform:uppercase;letter-spacing:-.04em;margin-bottom:5rem;position:relative;z-index:1;opacity:.06;pointer-events:none}
.techstack-pills-wrap{position:relative;z-index:1;display:flex;flex-direction:column;gap:3rem;width:1200px;max-width:calc(100% - 80px)}
.stack-category{background:var(--surface);border:1px solid var(--border);border-radius:18px;padding:2rem}
.cat-label{font-size:1.1rem;font-weight:700;margin-bottom:1.5rem;color:var(--fg);display:flex;align-items:center;gap:.7rem}
.cat-label::before{content:'';display:block;width:18px;height:2px;background:var(--accent)}
.cat-pills{display:flex;flex-wrap:wrap;gap:1rem}
.tech-pill{display:flex;align-items:center;gap:.8rem;padding:.8rem 1.3rem;background:rgba(0,0,0,.3);border:1px solid var(--border);border-radius:12px;font-size:.9rem;font-weight:500;transition:all .3s;cursor:default}
.tech-pill img{width:24px;height:24px}
.tech-pill:hover{transform:translateY(-5px);border-color:var(--accent);box-shadow:0 10px 24px rgba(194,164,255,.15);background:rgba(194,164,255,.05)}

/* PROJECTS */
.proj-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:1.5rem}
.proj-card{display:flex;flex-direction:column;background:var(--surface);border:1px solid var(--border);border-radius:16px;overflow:hidden;transition:all .4s cubic-bezier(.19,1,.22,1);cursor:pointer}
.proj-card:hover{transform:translateY(-8px);border-color:rgba(194,164,255,.3);box-shadow:0 20px 40px rgba(194,164,255,.12)}
.proj-card.featured{grid-column:span 2;flex-direction:row}
.pc-img{width:100%;height:220px;position:relative;overflow:hidden;border-bottom:1px solid var(--border)}
.proj-card.featured .pc-img{width:55%;height:100%;border-bottom:none;border-right:1px solid var(--border)}
.pc-img img{width:100%;height:100%;object-fit:cover;transition:transform .6s cubic-bezier(.19,1,.22,1);filter:brightness(.85)}
.proj-card:hover .pc-img img{transform:scale(1.06);filter:brightness(1)}
.pc-overlay{position:absolute;inset:0;background:rgba(194,164,255,.2);display:flex;align-items:center;justify-content:center;opacity:0;transition:opacity .4s}
.pc-overlay i{font-size:3rem;color:#fff;transform:translateY(20px);transition:transform .4s}
.proj-card:hover .pc-overlay{opacity:1}
.proj-card:hover .pc-overlay i{transform:translateY(0)}
.pc-body{padding:1.8rem;flex:1;display:flex;flex-direction:column}
.proj-card.featured .pc-body{width:45%}
.pc-top{display:flex;justify-content:space-between;align-items:center;margin-bottom:1rem}
.pc-badge{padding:.3rem .8rem;background:rgba(194,164,255,.1);color:var(--accent);border:1px solid rgba(194,164,255,.2);border-radius:20px;font-size:.68rem;font-weight:700;text-transform:uppercase;letter-spacing:.05em}
.pc-badge.go{background:rgba(6,182,212,.1);color:#06b6d4;border-color:rgba(6,182,212,.2)}
.pc-badge.spring{background:rgba(34,197,94,.1);color:#22c55e;border-color:rgba(34,197,94,.2)}
.pc-badge.mern{background:rgba(236,72,153,.1);color:#ec4899;border-color:rgba(236,72,153,.2)}
.pc-badge.django{background:rgba(245,158,11,.1);color:#f59e0b;border-color:rgba(245,158,11,.2)}
.pc-num{font-size:1.6rem;font-weight:800;color:rgba(255,255,255,.07)}
.pc-body h3{font-size:1.3rem;font-weight:700;margin-bottom:.7rem;color:var(--fg)}
.pc-body p{color:var(--muted);font-size:.9rem;margin-bottom:1.2rem;line-height:1.7;flex:1}
.pc-body p strong{color:var(--fg)}
.pc-tags{display:flex;flex-wrap:wrap;gap:.5rem}
.pc-tags span{font-family:monospace;font-size:.73rem;color:var(--muted)}
.pc-tags span:not(:last-child)::after{content:'·';margin-left:.5rem;color:var(--border)}
.proj-card.sm{background:rgba(255,255,255,.02)}
@media(max-width:900px){.proj-grid{grid-template-columns:repeat(2,1fr)}.proj-card.featured{flex-direction:column;grid-column:span 2}.proj-card.featured .pc-img{width:100%;height:220px;border-right:none;border-bottom:1px solid var(--border)}.proj-card.featured .pc-body{width:100%}}
@media(max-width:600px){.proj-grid{grid-template-columns:1fr}.proj-card.featured{grid-column:span 1}}

/* CERTS */
.cert-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:1.2rem}
.cert-card{background:var(--surface);border:1px solid var(--border);border-radius:16px;padding:1.5rem;display:flex;align-items:center;gap:1rem;transition:all .4s;cursor:default}
.cert-card:hover{transform:translateY(-5px);border-color:var(--ci);box-shadow:0 10px 30px rgba(0,0,0,.5)}
.cert-icon{width:48px;height:48px;border-radius:12px;background:rgba(255,255,255,.03);border:1px solid var(--border);display:flex;align-items:center;justify-content:center;font-size:1.4rem;color:var(--ci);flex-shrink:0}
.cert-info strong{display:block;font-size:.9rem;margin-bottom:.3rem;color:var(--fg)}
.cert-info span{font-size:.73rem;color:var(--muted);font-family:monospace}
@media(max-width:900px){.cert-grid{grid-template-columns:repeat(2,1fr)}}
@media(max-width:500px){.cert-grid{grid-template-columns:1fr}}

/* LEADERSHIP */
.lead-section{padding-top:8rem;padding-bottom:8rem}
.lead-marquee-wrap{overflow:hidden;padding:1.5rem 0;border-top:1px solid var(--border);border-bottom:1px solid var(--border);background:rgba(0,0,0,.2);margin:3rem 0}
.lead-marquee{display:flex}
.lm-track{display:flex;gap:3rem;white-space:nowrap;width:max-content;animation:lmq 30s linear infinite}
.lm-track span{font-size:1.15rem;font-weight:600;color:var(--muted);display:flex;align-items:center;gap:.8rem}
.lm-track span i{color:var(--accent)}
@keyframes lmq{to{transform:translateX(-50%)}}
.event-pills{display:flex;flex-wrap:wrap;justify-content:center;gap:1rem;margin-top:0}
.epill{padding:.75rem 1.4rem;background:var(--surface);border:1px solid var(--border);border-radius:40px;font-weight:500;font-size:.88rem;display:flex;align-items:center;gap:.6rem;transition:all .3s;cursor:default}
.epill i{color:var(--accent)}
.epill:hover{border-color:var(--accent);background:rgba(194,164,255,.08);transform:translateY(-3px)}

/* CONTACT */
.contact-wrap{display:grid;grid-template-columns:1fr 1.2fr;gap:5rem;align-items:start;background:var(--surface);border:1px solid var(--border);border-radius:24px;padding:4rem;overflow:hidden;position:relative}
.contact-wrap::before{content:'';position:absolute;top:-50%;right:-20%;width:60%;height:150%;background:radial-gradient(ellipse,rgba(194,164,255,.1),transparent 60%);pointer-events:none}
.contact-left{position:relative;z-index:1}
.contact-left .sec-title{margin-bottom:1rem}
.contact-left p{color:var(--muted);font-size:1rem;line-height:1.8;margin-bottom:2.5rem}
.contact-links{display:flex;flex-direction:column;gap:1.5rem;margin-bottom:2.5rem}
.clink{display:flex;align-items:center;gap:1rem;font-size:1rem;font-weight:500;transition:color .3s;color:var(--fg)}
.clink-icon{width:44px;height:44px;background:rgba(255,255,255,.05);border:1px solid var(--border);border-radius:12px;display:flex;align-items:center;justify-content:center;font-size:1.3rem;color:var(--accent);transition:all .3s;flex-shrink:0}
.clink:hover .clink-icon{background:var(--accent);border-color:var(--accent);color:#0b080c;transform:scale(1.1)}
.clink:hover span{color:var(--accent)}
.contact-socials{display:flex;gap:.8rem}
.contact-form{background:rgba(0,0,0,.4);padding:2.5rem;border-radius:20px;border:1px solid var(--border);position:relative;z-index:1;display:flex;flex-direction:column;gap:1.2rem}
.cf-field{position:relative}
.cf-field i{position:absolute;top:1.1rem;left:1.2rem;color:var(--muted);font-size:1.1rem}
.cf-field.ta i{top:1.2rem}
.cf-field input,.cf-field textarea{width:100%;padding:1rem 1rem 1rem 3rem;background:rgba(255,255,255,.03);border:1px solid var(--border);border-radius:12px;font-family:var(--font);font-size:.92rem;color:var(--fg);outline:none;transition:all .3s;resize:none}
.cf-field input::placeholder,.cf-field textarea::placeholder{color:var(--muted)}
.cf-field input:focus,.cf-field textarea:focus{border-color:var(--accent);background:rgba(194,164,255,.04);box-shadow:0 0 0 4px rgba(194,164,255,.08)}
@media(max-width:768px){.contact-wrap{grid-template-columns:1fr;padding:2rem;gap:2rem}}

/* FOOTER */
footer{padding:2.5rem 0;border-top:1px solid var(--border);background:rgba(0,0,0,.4)}
.footer-inner{display:flex;align-items:center;justify-content:space-between}
.f-brand{font-size:1.5rem;font-weight:800;color:var(--fg)}
.f-copy{font-size:.82rem;color:var(--muted);display:flex;align-items:center;gap:.4rem}
.f-links{display:flex;gap:1rem}
.f-links a{font-size:1.3rem;color:var(--muted);transition:color .3s}
.f-links a:hover{color:var(--accent)}
@media(max-width:600px){.footer-inner{flex-direction:column;gap:1.2rem;text-align:center}}

/* TILT */
.tilt-card{transform-style:preserve-3d;will-change:transform}

/* SCROLLBAR */
::-webkit-scrollbar{width:5px}
::-webkit-scrollbar-track{background:transparent}
::-webkit-scrollbar-thumb{background:var(--accent);border-radius:5px}
::selection{background:rgba(194,164,255,.3);color:var(--fg)}

